INSERT INTO experience (company, position, duration, description) VALUES ('AIA Philippines – Crizaldo Financial Associates ', 'Intern – Graphic Designer/Digital Marketer', 'February 2022 – May 2022', '["Aided the marketing team in creating graphic design and visual content for printed materials, banners, brochures, and calendars used for promoting the agency. Created graphics were used as promotional materials for digital marketing.","Utilized social media platforms and online office tools to promote the agency and encourage individuals to avail the products and services of the agency. Approximately 40 individuals were encouraged to attend the free webinar of the company."]');
INSERT INTO experience (company, position, duration, description) VALUES ('Freelance', 'Web Developer', 'January 2025 – January 2026', '["Designed and developed a web-based parish transaction and reservation system using PHP, MySQL, HTML, CSS, and JavaScript to manage event bookings, payments, and records.","Implemented responsive, mobile-friendly layouts ensuring consistent performance across devices.","Optimized PHP scripts and MySQL queries, improving load times and system performance."]');
INSERT INTO experience (company, position, duration, description) VALUES ('Freelance', 'Graphic Designer', 'January 2024 – present', '["Created custom wedding and birthday invitations, logos, and marketing graphics for small businesses, including a milk tea store.","Designed banners and tarpaulins for events and promotions, ensuring print-ready quality.","Delivered visually compelling work using Adobe Photoshop, and Adobe InDesign, meeting tight client deadlines."]');
INSERT INTO experience (company, position, duration, description) VALUES ('Schneider Electric', 'Order Entry Administrator', 'June 2023 – April 2025', '["Supported internal digital systems and streamlined order processing using SAP S/4HANA, ensuring accuracy and efficiency in cross-functional operations.","Collaborated across departments to resolve order discrepancies, automate workflows, and improve system reliability—skills transferable to software and system process optimization.","Led onboarding sessions and provided technical guidance to new hires, including system navigation and data entry best practices.","Acted as a key support point for digital operations, reflecting adaptability, attention to detail, and the ability to manage complex systems—valuable traits for backend and systems development roles."]');
