INSERT INTO projects (title, technology, link, description) VALUES ('CVSU Entrance Exam System', 'Laravel, Vue.js, Tailwind CSS, BotMan, Twilio', 'https://github.com/dlxks/cvsu-ees.git', '["Prototype entrance exam platform developed for Cavite State University to digitize exam administration","Integrated a basic chatbot using BotMan and Twilio for guidance, FAQs, and automated student assistance","Fullstack web application built with Laravel (backend) and Vue.js (frontend), styled with Tailwind CSS"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Student Management System', 'HTML, CSS, JavaScript, PHP, MySQL', 'https://github.com/dlxks/sims.git', '["Web-based platform designed for managing student records and school-related data","Supports CRUD operations for student profiles including enrollment, grades, and personal details","Responsive front-end built with Bootstrap, with backend integration in PHP and MySQL database"]');
INSERT INTO projects (title, technology, link, description) VALUES ('React Portfolio', 'React, Bootstrap, AOS, Iconify', 'https://github.com/dlxks/react-portfolio.git', '["Responsive personal portfolio showcasing projects, skills, and experiences","Implemented smooth scroll animations using AOS for a dynamic user experience","Custom icon sets integrated with Iconify and styled with Bootstrap for modern design consistency"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Little Lemon Restaurant', 'React, Next.js, Tailwind CSS', 'https://github.com/dlxks/little-lemon.git', '["Restaurant-themed web application with features for table reservation, menu browsing, and booking management","Developed using Next.js 13 App Router for optimized routing and scalability","State management handled via Context API for persistent user sessions and cart functionality","Enhanced user experience with interactive UI components such as modals and toast notifications"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Memeify', 'React, CSS, HTML', 'https://github.com/dlxks/memeify.git', '["Lightweight meme generator enabling users to create, edit, and share custom memes instantly","Supports drag-and-drop image uploads with live preview functionality","Designed with a responsive layout ensuring seamless use across desktop and mobile devices"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Yummify', 'React, REST API, CSS', 'https://github.com/dlxks/yummify.git', '["Recipe discovery application powered by REST API integration for real-time data","Allows users to search recipes by ingredients, categories, or cuisine preferences","Features step-by-step cooking instructions with a clean and intuitive user interface"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Tenzies Dice Game', 'React, CSS, JavaScript', 'https://github.com/dlxks/tenzies.git', '["Interactive dice game where players roll dice until all match a target number","Includes win condition tracking, score recording, and game reset functionality","Playful and responsive UI design with smooth animations for an engaging user experience"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Code Rescue: Word Quest', 'React, CSS, JavaScript', 'https://github.com/dlxks/wordquest.git', '["Educational word puzzle game with a coding-inspired rescue mission theme","Progressive levels of difficulty to challenge players’ problem-solving and vocabulary","Clean and responsive UI design optimized for both desktop and mobile play"]');
INSERT INTO projects (title, technology, link, description) VALUES ('VanLife - Van Rental Platform', 'React, TypeScript, Vite, Tailwind CSS', 'https://github.com/dlxks/vanlife.git', '["Front-end design van rental platform designed for both travelers and van hosts","Advanced filtering and sorting options by van type (Simple, Rugged, Luxury) with dynamic UI updates","Host dashboard to manage van listings, availability, and customer reviews","Implemented simple secure authentication with protected routes and role-based access","Mobile-first approach using Tailwind CSS with scalable front-end architecture powered by Vite and TypeScript"]');
INSERT INTO projects (title, technology, link, description) VALUES ('Marci Metzger Landing Page', 'Next.js, Tailwind CSS', 'https://github.com/dlxks/marci-metzger.git', '["Modern landing page redesign for Marci Metzger’s real estate services","Responsive Next.js application showcasing property listings and services","Hero and About sections with engaging CTAs and detailed service info","Property highlights, gallery, and search functionality for easy browsing","Contact form and interactive map for seamless customer engagement","Deployed on Vercel with performance-optimized Next.js features"]');
